mapper.update:
BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_NO START WITH 1 INCREMENT BY 1';
END;

BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_PLACE_TAG_MAP_NO';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_PLACE_TAG_MAP_NO START WITH 1 INCREMENT BY 1';
END;

BEGIN
	EXECUTE IMMEDIATE 'DROP SEQUENCE SEQ_HOURS_ID';
EXCEPTION
	WHEN OTHERS THEN
		IF SQLCODE != -2289 THEN
			RAISE;
		END IF;
END;

BEGIN
	EXECUTE IMMEDIATE 'CREATE SEQUENCE SEQ_HOURS_ID START WITH 1 INCREMENT BY 1';
END;

mapper.insert:
		INSERT INTO PLACE (
        PLACE_NO, PLACE_CONTENT_ID, PLACE_NAME, PLACE_CATEGORY, PLACE_ADDRESS, 
        PLACE_LATITUDE, PLACE_LONGITUDE, PLACE_RATING, 
        PLACE_NUMBER, PLACE_THUMBNAIL_URL
    ) VALUES (
        #{placeNo}, #{placeContentId}, #{placeName}, #{placeCategory}, #{placeAddress},
        #{placeLatitude}, #{placeLongitude}, 0, 
        #{placeNumber}, #{placeThumbnailUrl}
    )

INSERT INTO PLACE_TAG_MAP (
	PLACE_TAG_NO, PLACE_NO, TAG_CODE, TAG_WEIGHT, TAG_SOURCE, TAG_CONFIDENCE
) VALUES (
	SEQ_PLACE_TAG_MAP_NO.NEXTVAL, #{placeNo}, #{tagCode}, #{tagWeight}, #{tagSource}, #{tagConfidence}
)

INSERT INTO PLACE_HOURS (
	HOURS_ID, PLACE_NO, DAY_OF_WEEK, OPEN_TIME, CLOSE_TIME,
	BREAK_STRAT_TIME, BREAK_END_TIME, LAST_ORDER, IS_CLOSED
) VALUES (
	SEQ_HOURS_ID.NEXTVAL, #{placeNo}, #{dayOfWeek}, #{openTime}, #{closeTime},
	#{breakStratTime}, #{breakEndTime}, #{lastOrder}, #{isClosed}
)
